- `useOrder.ts`, `useTablet.ts`, `useReservation.ts`, `useCheckIn.ts`, `useCheckout.ts`
- **NO** `useTableOperations.ts`, **NO** `useTableTransfer`, etc. (glob for `*operation*`, `*transfer*`, `*split*` returned nothing; `*merge*` only matched a docs report).

### Components (`src/components/reception/`)
- `ManagerAuthModal.vue`, `FloorViewFooter.vue`, `HamburgerMenu.vue`, `PaymentMethodSelector.vue`, `SidebarNavigation.vue`
- **NO** `TableOperationsMenu.vue` or `TableTransferModal.vue` exist anywhere.

---

## 2 & 3. The "TableOperationsMenu" + "TableTransferModal" (inline in ReceptionOrderView.vue)

These are not components — they are inline template + script. Here is exactly where they live and how they work:

### A) The context menu (= the operations menu) — opened on table DOUBLE-CLICK
**Trigger** (template, table cards ~L1025):
```
@click="handleTableClick(table)"
@dblclick="handleTableDoubleClick(table, $event)"
```
**Handler + state + config** (script, ~L4863-5045):
```ts
// ===== CONTEXT MENU STATE =====
const showTableContextMenu = ref(false);
const selectedTableForAction = ref<any>(null);
const contextMenuPosition = ref({ x: 0, y: 0 });

// Modal states (declared but only split-item/cancel actually use modals)
const showTransferModal = ref(false);   // NOT actually rendered as a modal
const showMergeModal = ref(false);       // NOT actually rendered as a modal
const showSplitOrderModal = ref(false);  // NOT actually rendered as a modal
const showSplitItemModal = ref(false);   // IS rendered (Modal 4 below)
const showCancelModal = ref(false);      // IS rendered (Modal 5)

// contextMenuStyle computed → auto-flips up if near bottom edge

function handleTableDoubleClick(table: any, event: MouseEvent) {
  selectedTableForAction.value = table;
  contextMenuPosition.value = { x: event.clientX, y: event.clientY };
  showTableContextMenu.value = true;
}

// The 6 actions. Empty tables only see "select_items".
const allTableActions = [
  { id: "select_items", label: "Chọn món", icon: "📝", colorClass: "bg-green-500 text-white", description: "Thêm món vào bàn", isPrimary: true },
  { id: "transfer",     label: "Chuyển bàn", icon: "🔁", colorClass: "bg-blue-500 text-white", description: "Di chuyển order sang bàn khác" },
  { id: "merge",        label: "Ghép phiếu", icon: "🔗", colorClass: "bg-purple-500 text-white", description: "Gộp order từ 2 bàn thành 1" },
  { id: "split-order",  label: "Tách phiếu", icon: "✂️", colorClass: "bg-orange-500 text-white", description: "Chia order thành nhiều phiếu" },
  { id: "split-item",   label: "Tách món", icon: "🍽️", colorClass: "bg-pink-500 text-white", description: "Tách riêng một số món" },
  { id: "cancel",       label: "Hủy phiếu", icon: "❌", colorClass: "bg-red-500 text-white", description: "Xóa toàn bộ order" },
];

const tableActions = computed(() => {
  const isEmpty = !selectedTableForAction.value || selectedTableForAction.value.status === "Available";
  return isEmpty ? allTableActions.filter(a => a.id === "select_items") : allTableActions;
});

function handleTableAction(actionId: string) {
  showTableContextMenu.value = false;
  const table = selectedTableForAction.value;
  if (!table) return;
  switch (actionId) {
    case "select_items": activeMainTab.value = "menu"; selectedTableCode.value = table.code; ...; break;
    case "transfer":  sourceTableCode.value = table.code; selectionMode.value = "transfer"; break;
    case "merge":     sourceTableCode.value = table.code; selectionMode.value = "merge"; break;
    case "split-order": sourceTableCode.value = table.code; selectionMode.value = "split-order"; break;
    case "split-item":  sourceTableCode.value = table.code; selectionMode.value = "split-item"; break;
