const selectedTableForAction = ref<any>(null);
const contextMenuPosition = ref({ x: 0, y: 0 });

// Modal states (declared but only split-item/cancel actually use modals)
const showTransferModal = ref(false);   // NOT actually rendered as a modal
const showMergeModal = ref(false);       // NOT actually rendered as a modal
const showSplitOrderModal = ref(false);  // NOT actually rendered as a modal
const showSplitItemModal = ref(false);   // IS rendered (Modal 4 below)
const showCancelModal = ref(false);      // IS rendered (Modal 5)

// contextMenuStyle computed → auto-flips up if near bottom edge

function handleTableDoubleClick(table: any, event: MouseEvent) {
  selectedTableForAction.value = table;
  contextMenuPosition.value = { x: event.clientX, y: event.clientY };
  showTableContextMenu.value = true;
}

// The 6 actions. Empty tables only see "select_items".
const allTableActions = [
  { id: "select_items", label: "Chọn món", icon: "📝", colorClass: "bg-green-500 text-white", description: "Thêm món vào bàn", isPrimary: true },
  { id: "transfer",     label: "Chuyển bàn", icon: "🔁", colorClass: "bg-blue-500 text-white", description: "Di chuyển order sang bàn khác" },
  { id: "merge",        label: "Ghép phiếu", icon: "🔗", colorClass: "bg-purple-500 text-white", description: "Gộp order từ 2 bàn thành 1" },
  { id: "split-order",  label: "Tách phiếu", icon: "✂️", colorClass: "bg-orange-500 text-white", description: "Chia order thành nhiều phiếu" },
